+    /// Acquire the best tier for a given token requirement
+    /// From edgebox's acquireForHeap() pattern
+    pub fn acquireForTokens(self: *ContextPool, required_tokens: u32) !*PooledContext {
+        // Find smallest tier that fits the requirement
+        for (TIER_SIZES, 0..) |size, tier_idx| {
+            if (size >= required_tokens) {
+                return self.acquire(tier_idx);
+            }
+        }
+
+        // No suitable tier - try largest tier as fallback
+        return self.acquire(TIER_SIZES.len - 1);
+    }
