+// D. New tests for edgebox-inspired features
+
+test "PooledContext: needsRealloc detection" {
+    // Verify needsRealloc detects mismatched tier configuration
+    var mock_ctx = PooledContext{
+        .ctx = undefined,
+        .tier = 1,
+        .n_ctx = TIER_SIZES[1], // 1024 - matches tier
+        .in_use = false,
+        .last_used = 0,
+        .usage_count = 0,
+    };
+
+    // Should not need realloc when tier matches
+    try std.testing.expect(!mock_ctx.needsRealloc());
+
+    // Corrupt the n_ctx value
+    mock_ctx.n_ctx = 999; // Mismatch!
+    try std.testing.expect(mock_ctx.needsRealloc());
+}
+
+test "ContextPool: acquireForTokens tier selection" {
+    // Verify acquireForTokens selects smallest fitting tier
+    // This is a structural test - verifies tier selection logic
+
+    // 256 tokens → tier 0 (512)
+    for (TIER_SIZES, 0..) |size, tier_idx| {
+        if (size >= 256) {
+            try std.testing.expectEqual(@as(usize, 0), tier_idx);
+            break;
+        }
+    }
+
+    // 600 tokens → tier 1 (1024)
+    for (TIER_SIZES, 0..) |size, tier_idx| {
+        if (size >= 600) {
+            try std.testing.expectEqual(@as(usize, 1), tier_idx);
+            break;
+        }
+    }
+
+    // 1500 tokens → tier 2 (2048)
+    for (TIER_SIZES, 0..) |size, tier_idx| {
+        if (size >= 1500) {
+            try std.testing.expectEqual(@as(usize, 2), tier_idx);
+            break;
+        }
+    }
+
+    // 3000 tokens → tier 3 (4096)
+    for (TIER_SIZES, 0..) |size, tier_idx| {
+        if (size >= 3000) {
+            try std.testing.expectEqual(@as(usize, 3), tier_idx);
+            break;
+        }
+    }
+}
